- (void)unzipIPAForVapp:(WBVAppModel *)vapp progressHandler:(void (^)(long, long))progressHandler completionHandler:(void (^)(NSString *, BOOL, NSError *))completionHandler {
    NSString *bundleId = vapp.bundleId;
    NSString *path = [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:bundleId]];
    NSString *dest = [_tmpRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:bundleId]];
    [NSFileManager.defaultManager removeItemAtPath:dest error:nil];
    if ([NSFileManager.defaultManager fileExistsAtPath:path] == FALSE) {
        completionHandler(nil, NO, nil);
    }
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        [SSZipArchive unzipFileAtPath:path toDestination:dest progressHandler:^(NSString * _Nonnull entry, unz_file_info zipInfo, long entryNumber, long total) {
            [NSThread wb_executeOnMainThread:^{
                progressHandler(entryNumber, total);
            }];
        } completionHandler:^(NSString * _Nonnull path, BOOL succeeded, NSError * _Nonnull error) {
            [NSThread wb_executeOnMainThread:^{
                // find the xxx.app dir under extracted dir, and call the completionHandler
                NSString *appDir = [self findTheAppDir:dest];
                if (appDir) {
                    vapp.userInfo.ipaUnzipPath = dest;
                    completionHandler(appDir, succeeded, error);
                } else {
                    completionHandler(nil, NO, nil);
                }
            }];
        }];
    });
}

- (NSString *)findTheAppDir:(NSString *)path {
    NSArray *dirArray = [NSFileManager.defaultManager contentsOfDirectoryAtPath:path error:nil];
    for (NSString *dir in dirArray) {
        if ([dir isEqualToString:@"__MACOSX"]) {
            continue;
        }
        NSString *subPath = [path stringByAppendingPathComponent:dir];
        BOOL isDir = FALSE;
        if ([NSFileManager.defaultManager fileExistsAtPath:subPath isDirectory:&isDir]) {
            if (isDir) {
                if ([subPath hasSuffix:@".app"]) {
                    return subPath;
                }
                NSString *result = [self findTheAppDir:subPath];
                if (result) {
                    return result;
                }
            }
        }
    }
    return nil;
}



