- (void)refreshToken:(WBNetworkBaseCallback)callback {
    uint32_t challenge1 = arc4random();
    uint32_t challenge2 = (challenge1 + 0x86868686) ^ 0xbeafbeaf;
    NSData *clientInfoData = [[WBQuery query] clientInfo].wb_JSONData;
    NSAssert(clientInfoData, @"client info serialize error");
    NSString *clientInfoString = [[NSString alloc] initWithData:clientInfoData encoding:NSUTF8StringEncoding];
    NSString *clientInfoBase64String = [clientInfoString wb_base64EncodedString];
    clientInfoString = [clientInfoString stringByAppendingString:@(challenge1).stringValue];
    unsigned char result[16];
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wdeprecated-declarations"
    NSData *sigData = [clientInfoString dataUsingEncoding:NSUTF8StringEncoding];
    CC_MD5(sigData.bytes, (CC_LONG)sigData.length, result);
#pragma clang diagnostic pop
    NSString *hash = [NSString stringWithFormat:@"%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X",result[0], result[1], result[2], result[3], result[4], result[5], result[6], result[7],result[8], result[9], result[10], result[11],result[12], result[13], result[14], result[15]];

    NSDictionary *params = @{
        @"ca" : clientInfoBase64String,
        @"cb" : [NSNumber numberWithUnsignedInt:challenge1],
        @"cc" : [NSNumber numberWithUnsignedInt:challenge2],
        @"signature" : hash,
    };

    [self POST:@"user/token" params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        if (error) return callback(nil, error);
        NSNumber *response = [json objectForKey:@"cr"];
        if (response) {
            uint32_t iresponse = (uint32_t)[response intValue];
            if (iresponse != ((challenge2 + 0x9E3A092B) ^ 0xAB88CD9E)) {
                if ([json respondsToSelector:@selector(removeObjectForKey:)]) {
                    [json removeObjectForKey:@"cr"];
                }
            }
        }
        callback(json, nil);
    }];
}


#pragma mark - Private

- (NSURLRequest *)createRequestWithURL:(NSString *)URL HTTPMethod:(NSString *)HTTPMethod params:(NSDictionary *)params isJsonContentType:(BOOL)isJsonContentType {
    // Create HTTP request.
    NSMutableURLRequest *request = [[NSMutableURLRequest alloc] init];
    request.HTTPMethod = HTTPMethod;
    // Authorize header field.
    if (WBSettingManager.sharedManager.Token) {
        [request addValue:[NSString stringWithFormat:@"Bearer %@", WBSettingManager.sharedManager.Token] forHTTPHeaderField:@"Authorization"];
    }

    // 动态设置 Content-Type
    NSString *contentType = isJsonContentType ? @"application/json" : @"application/x-www-form-urlencoded";
    [request addValue:contentType forHTTPHeaderField:@"Content-Type"];

    // Config POST.
    URL = [self validateUrlString:URL];
    if ([[HTTPMethod uppercaseString] isEqualToString:@"POST"]) {
        if (isJsonContentType) {
            // JSON
            request.HTTPBody = params.wb_JSONData;
        } else {
            // 表单
            request.HTTPBody = params.wb_URLEncodedData;
        }
    // Config GET.
    } else if ([[HTTPMethod uppercaseString] isEqualToString:@"GET"] || !HTTPMethod.length) {
        if (params.count) {
            URL = [URL stringByAppendingFormat:@"?%@", params.wb_URLEncodedString];
        }
    // Fall on unexpected HTTP methods.
    } else {
        NSAssert(NO, @"unexpected HTTP request method");
    }
    request.URL = [NSURL URLWithString:URL];
    return request;
}

- (NSString *)validateUrlString:(NSString *)urlStr {
    NSURL *url = [NSURL URLWithString:urlStr];
    if (url.scheme.length && url.host.length && url.path) return urlStr;
    return [[self.baseURL absoluteString] stringByAppendingPathComponent:urlStr];
}

- (NSURLRequest *)createMultipartRequestWithURL:(NSString *)URL params:(NSDictionary *)params {
    // Create HTTP request.
    NSMutableURLRequest *request = [[NSMutableURLRequest alloc] init];
    request.HTTPMethod = @"POST";
    NSURL *absoluteURL = [self.baseURL URLByAppendingPathComponent:URL];
     request.URL = absoluteURL;
    // Authorize header field.
    if (WBSettingManager.sharedManager.Token) {
        [request addValue:[NSString stringWithFormat:@"Bearer %@", WBSettingManager.sharedManager.Token] forHTTPHeaderField:@"Authorization"];
    }

    // Set up boundary.
    NSString *boundary = [NSString stringWithFormat:@"Boundary-%@", [[NSUUID UUID] UUIDString]];
    [request addValue:[NSString stringWithFormat:@"multipart/form-data; boundary=%@",boundary] forHTTPHeaderField:@"Content-Type"];
    // Set up data in request body.
    NSMutableData *postData = [[NSMutableData alloc] init];

    for (NSString *key in params) {
        id value = [params objectForKey:key];
        NSMutableString *pair = [NSMutableString stringWithFormat:@"--%@\r\nContent-Disposition: form-data; name=\"%@\"", boundary, key];
        if ([value isKindOfClass:[NSURL class]]) {
            NSString *fileName = [value lastPathComponent];
            [pair appendString:[NSString stringWithFormat:@"; filename=\"%@\"\r\n", fileName]];
//            [pair appendString:[NSString stringWithFormat:@"; filename=\"hello.txt\"\r\n"]];
            // Append file type, default is image.
//            [pair appendString:[NSString stringWithFormat:@"Content-Type=text/plain"]];
            [pair appendString:[NSString stringWithFormat:@"Content-Type=image/%@", fileName.pathExtension]];
        }
        [pair appendString:@"\r\n\r\n"];
        [postData appendData:[pair dataUsingEncoding:NSUTF8StringEncoding]];

        if ([value isKindOfClass:[NSString class]]) {
            NSData *strData = [value dataUsingEncoding:NSUTF8StringEncoding];
            [postData appendData:strData];
        } else if ([value isKindOfClass:[NSData class]]) {
            [postData appendData:value];
        } else if ([value isKindOfClass:[NSURL class]]) {
            NSData *fileData = [NSData dataWithContentsOfURL:value];
            [postData appendData:fileData];
        }
        [postData appendData:[@"\r\n" dataUsingEncoding:NSUTF8StringEncoding]];
    }
    [postData appendData:[[NSString stringWithFormat:@"--%@--\r\n",boundary] dataUsingEncoding:NSUTF8StringEncoding]];
    request.HTTPBody = postData;
    return request;
}
- (void)checkoutWithResponse:(NSURLResponse * _Nullable)response bodyData:(NSData * _Nullable)bodyData error:(NSError * _Nullable)error callback:(void (^)(id _Nullable json, NSError * _Nullable error))callback {

    if (error) return callback(nil, error);
    // Checkout response.
    NSAssert(response, @"response is null");
    NSAssert([response isKindOfClass:[NSHTTPURLResponse class]], @"response is not http response");
    NSHTTPURLResponse *httpResponse = (NSHTTPURLResponse *)response;

    // Checkout status code.
    switch (httpResponse.statusCode) {
        case 200: {
            // Checkout data in response.
            NSAssert(bodyData, @"data is null");
            NSError *serializeError = nil;
            id json = [NSJSONSerialization JSONObjectWithData:bodyData options:NSJSONReadingFragmentsAllowed error:&serializeError];
            if (serializeError) return callback(nil, serializeError);
            // Assert if request success with status code 200, message in response json always 'success'.
            if ([json[@"message"] isEqualToString:@"success"]) {
                id data = json[@"data"];
                return callback(data, nil);
            } else if ([json[@"message"] isEqualToString:@"error"]) {
                NSError *error = [NSError errorWithDomain:WBNetworkRequestErrorDomain code:httpResponse.statusCode userInfo:@{NSLocalizedDescriptionKey:json[@"data"][@"description"]}];
                callback(nil, error);
            } else {
                NSError *error = [NSError errorWithDomain:WBNetworkRequestErrorDomain code:httpResponse.statusCode userInfo:@{NSLocalizedDescriptionKey:@"未知网络错误"}];
                callback(nil, error);
            }
            break;
        }

        // Fall on other status code.
        default: {
            NSError *error = [NSError errorWithDomain:WBNetworkRequestErrorDomain code:httpResponse.statusCode userInfo:@{NSLocalizedDescriptionKey:@"网络请求错误"}];
            // Throw as error to callback block.
            return callback(nil, error);
        }
    }
}

