@implementation WBOperationTraceRecorder

+ (dispatch_queue_t)traceQueue {
    static dispatch_queue_t queue = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        queue = dispatch_queue_create("com.webox.operation.trace", DISPATCH_QUEUE_SERIAL);
        dispatch_queue_set_specific(queue, kWBOperationTraceQueueSpecificKey, (void *)kWBOperationTraceQueueSpecificKey, NULL);
    });
    return queue;
}

+ (NSString *)traceFilePath {
    NSString *documentsPath = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject;
    if (documentsPath.length == 0) {
        documentsPath = NSTemporaryDirectory();
    }
    return [documentsPath stringByAppendingPathComponent:kWBOperationTraceFileName];
}

+ (NSURL *)traceFileURL {
    return [NSURL fileURLWithPath:[self traceFilePath]];
}

+ (void)appendAction:(NSString *)action
       usageSnapshot:(NSDictionary<NSString *,NSNumber *> *)usageSnapshot
         extraFields:(NSDictionary *)extraFields {
    if (action.length == 0) {
        return;
    }
    dispatch_block_t writeBlock = ^{
        NSMutableDictionary *entry = [NSMutableDictionary dictionary];
        entry[@"time"] = [self currentTimeString];
        entry[@"action"] = action;
        entry[@"appUsedTimeInSecond"] = usageSnapshot[@"appUsedTimeInSecond"] ?: @(0);
        entry[@"vappUsedTimeInSecond"] = usageSnapshot[@"vappUsedTimeInSecond"] ?: @(0);
        entry[@"backgroundUsedTimeInSecond"] = usageSnapshot[@"backgroundUsedTimeInSecond"] ?: @(0);
        NSDictionary *sanitizedExtraFields = [self sanitizedJSONObject:extraFields];
        if ([sanitizedExtraFields isKindOfClass:NSDictionary.class]) {
            [entry addEntriesFromDictionary:sanitizedExtraFields];
        }
        NSError *error = nil;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:entry options:0 error:&error];
        if (error || jsonData.length == 0) {
            NSLog(@"OperationTrace serialize failed: %@", error.localizedDescription);
            return;
        }
        NSMutableData *lineData = [jsonData mutableCopy];
        [lineData appendData:[@"\n" dataUsingEncoding:NSUTF8StringEncoding]];
        NSString *filePath = [self traceFilePath];
        [self ensureTraceFileReadyAtPath:filePath];
        NSFileHandle *fileHandle = [NSFileHandle fileHandleForWritingAtPath:filePath];
        if (!fileHandle) {
            NSLog(@"OperationTrace open file failed");
            return;
        }
        if (@available(iOS 13.0, *)) {
            [fileHandle seekToEndReturningOffset:nil error:nil];
            [fileHandle writeData:lineData error:nil];
            [fileHandle closeAndReturnError:nil];
        } else {
            [fileHandle seekToEndOfFile];
            [fileHandle writeData:lineData];
            [fileHandle closeFile];
        }
    };
    if (dispatch_get_specific(kWBOperationTraceQueueSpecificKey)) {
        writeBlock();
    } else {
        dispatch_sync([self traceQueue], writeBlock);
    }
}

+ (void)ensureTraceFileReadyAtPath:(NSString *)filePath {
    NSString *directoryPath = filePath.stringByDeletingLastPathComponent;
    if (![NSFileManager.defaultManager fileExistsAtPath:directoryPath]) {
        [NSFileManager.defaultManager createDirectoryAtPath:directoryPath withIntermediateDirectories:YES attributes:nil error:nil];
    }
    if (![NSFileManager.defaultManager fileExistsAtPath:filePath]) {
        [NSFileManager.defaultManager createFileAtPath:filePath contents:nil attributes:nil];
    }
}

+ (NSString *)currentTimeString {
    static NSDateFormatter *formatter = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        formatter = [[NSDateFormatter alloc] init];
        formatter.locale = [[NSLocale alloc] initWithLocaleIdentifier:@"zh_CN"];
        formatter.dateFormat = @"yyyy-MM-dd HH:mm:ss.SSS";
    });
    return [formatter stringFromDate:[NSDate date]];
}

+ (id)sanitizedJSONObject:(id)obj {
    if (!obj || obj == NSNull.null) {
        return nil;
    }
    if ([obj isKindOfClass:NSString.class] ||
        [obj isKindOfClass:NSNumber.class] ||
        [obj isKindOfClass:NSNull.class]) {
        return obj;
    }
    if ([obj isKindOfClass:NSURL.class]) {
        return [(NSURL *)obj absoluteString] ?: obj.description;
    }
    if ([obj isKindOfClass:NSError.class]) {
        NSError *error = (NSError *)obj;
        return @{
            @"domain": error.domain ?: @"",
            @"code": @(error.code),
            @"description": error.localizedDescription ?: @""
        };
    }
    if ([obj isKindOfClass:NSDate.class]) {
        return [self currentTimeString];
    }
    if ([obj isKindOfClass:NSArray.class]) {
        NSMutableArray *items = [NSMutableArray array];
        for (id item in (NSArray *)obj) {
            id sanitizedItem = [self sanitizedJSONObject:item];
            [items addObject:sanitizedItem ?: NSNull.null];
        }
        return items;
    }
    if ([obj isKindOfClass:NSDictionary.class]) {
        NSMutableDictionary *dict = [NSMutableDictionary dictionary];
        [(NSDictionary *)obj enumerateKeysAndObjectsUsingBlock:^(id key, id value, BOOL *stop) {
            NSString *sanitizedKey = [key isKindOfClass:NSString.class] ? key : [key description];
            id sanitizedValue = [self sanitizedJSONObject:value];
            dict[sanitizedKey] = sanitizedValue ?: NSNull.null;
        }];
        return dict;
    }
    return [obj description];
}

@end

